import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, ObjectLiteral } from 'typeorm';
import { Agency } from '../agencies/agency.entity';
import { SpendingRecord } from '../spending/spending-record.entity';
import { GeoSpendingSnapshot } from '../geography/geo-spending-snapshot.entity';
import { DisasterFundingRecord } from '../disaster/disaster-funding-record.entity';
import { DisasterRecoveryRatio } from '../disaster/disaster-recovery-ratio.entity';
import { UsaSpendingService } from './usa-spending.service';
import { OpenFemaService } from './openfema.service';
import { computeRecoveryRatio } from './recovery-ratio';
import { Cron } from '@nestjs/schedule';

const SYNC_FISCAL_YEAR = 2024;
const SYNC_DEF_GROUP = 'L';

const AGENCIES_AND_SPENDING = 'agencies_and_spending';
const GEOGRAPHY = 'geography';
const DISASTER = 'disaster';

type SyncStatus = 'running' | 'success' | 'error';
type SyncStatusEntry = { module: string; lastSyncAt: Date; status: SyncStatus };

@Injectable()
export class SyncService {
  private readonly statusMap = new Map<string, SyncStatusEntry>();

  constructor(
    @InjectRepository(Agency) private readonly agencyRepo: Repository<Agency>,
    @InjectRepository(SpendingRecord) private readonly spendingRepo: Repository<SpendingRecord>,
    @InjectRepository(GeoSpendingSnapshot) private readonly geoRepo: Repository<GeoSpendingSnapshot>,
    @InjectRepository(DisasterFundingRecord) private readonly disasterRepo: Repository<DisasterFundingRecord>,
    @InjectRepository(DisasterRecoveryRatio) private readonly ratioRepo: Repository<DisasterRecoveryRatio>,
    private readonly usaService: UsaSpendingService,
    private readonly femaService: OpenFemaService,
  ) {}

  getStatus(): { [module: string]: SyncStatusEntry } {
    return Object.fromEntries(this.statusMap);
  }

  private markStatus(module: string, status: SyncStatus): void {
    this.statusMap.set(module, { module, lastSyncAt: new Date(), status });
  }

  private async runWithStatus(
    module: string,
    work: () => Promise<void>,
  ): Promise<void> {
    this.markStatus(module, 'running');
    try {
      await work();
      this.markStatus(module, 'success');
    } catch (e) {
      console.error(`[Sync] ${module} failed:`, e instanceof Error ? e.message : e);
      this.markStatus(module, 'error');
    }
  }

  private async upsertBy<T extends ObjectLiteral>(
    repo: Repository<T>,
    entity: T,
    conflictColumns: string[],
  ): Promise<void> {
    await repo.upsert(entity, conflictColumns);
  }

  async syncAgenciesAndSpending(): Promise<void> {
    await this.runWithStatus(AGENCIES_AND_SPENDING, async () => {
      const agenciesResult = await this.usaService.fetchAgencies();
      if (agenciesResult.status === 'success') {
        for (const agency of agenciesResult.agencies) {
          await this.upsertBy(
            this.agencyRepo,
            agency,
            ['toptierCode'],
          );
        }
      }

      const spendingResult = await this.usaService.fetchSpendingByAgency({
        agency: '',
        fiscalYear: SYNC_FISCAL_YEAR,
      });
      if (spendingResult.status === 'success') {
        for (const record of spendingResult.rows) {
          await this.upsertBy(
            this.spendingRepo,
            record,
            ['agencyId', 'fiscalYear', 'quarter', 'awardTypeLabel'],
          );
        }
      }
    });
  }

  async syncGeography(): Promise<void> {
    await this.runWithStatus(GEOGRAPHY, async () => {
      const geoResult = await this.usaService.fetchGeoSnapshots({
        agency: '',
        fiscalYear: SYNC_FISCAL_YEAR,
        scope: 'recipient',
      });
      if (geoResult.status === 'success') {
        for (const snapshot of geoResult.rows) {
          await this.upsertBy(
            this.geoRepo,
            snapshot,
            ['stateCode', 'fiscalYear', 'agencyId', 'scope'],
          );
        }
      }
    });
  }

  async syncDisaster(): Promise<void> {
    await this.runWithStatus(DISASTER, async () => {
      const disasterResult = await this.usaService.fetchDisasterSpending(SYNC_DEF_GROUP);
      const fedSpendingByState = new Map<string, number>();
      if (disasterResult.status === 'success') {
        for (const record of disasterResult.rows) {
          await this.upsertBy(
            this.disasterRepo,
            record,
            ['defGroup', 'stateCode'],
          );
          fedSpendingByState.set(
            record.stateCode,
            (fedSpendingByState.get(record.stateCode) ?? 0) + record.obligatedAmount,
          );
        }
      }

      const femaDeclarations = await this.femaService.fetchDeclarationsByState();
      for (const decl of femaDeclarations) {
        const fedSpending = fedSpendingByState.get(decl.stateCode) ?? 0;
        const ratio = computeRecoveryRatio(decl.femaObligatedCents, fedSpending);
        await this.ratioRepo.upsert(
          {
            stateCode: decl.stateCode,
            stateName: decl.stateName,
            fiscalYear: decl.fiscalYear,
            femaObligated: decl.femaObligatedCents,
            fedSpendingObligated: fedSpending,
            declarationCount: decl.declarationCount,
            recoveryRatio: ratio,
            dominantIncidentType: decl.dominantIncidentType,
          },
          ['stateCode', 'fiscalYear'],
        );
      }
    });
  }

  @Cron('0 2 * * *')
  async syncAll(): Promise<void> {
    await this.syncAgenciesAndSpending();
    await this.syncGeography();
    await this.syncDisaster();
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { SyncService } from './sync.service';
import { UsaSpendingService } from './usa-spending.service';
import { OpenFemaService } from './openfema.service';
import { Agency } from '../agencies/agency.entity';
import { SpendingRecord } from '../spending/spending-record.entity';
import { GeoSpendingSnapshot } from '../geography/geo-spending-snapshot.entity';
import { DisasterFundingRecord } from '../disaster/disaster-funding-record.entity';
import { DisasterRecoveryRatio } from '../disaster/disaster-recovery-ratio.entity';
import { StateAggregationResult } from './openfema.service';

describe('SyncService', () => {
  let service: SyncService;
  let agencyRepo: { upsert: jest.Mock };
  let spendingRepo: { upsert: jest.Mock };
  let geoRepo: { upsert: jest.Mock };
  let disasterRepo: { upsert: jest.Mock };
  let ratioRepo: { upsert: jest.Mock };
  let usaService: UsaSpendingService;
  let femaService: OpenFemaService;

  interface TestCase {
    name: string;
    method: string;
    agencyFetchResult?: { status: string; agencies?: any[] };
    spendingFetchResult?: { status: string; rows?: any[]; total?: number };
    geoFetchResult?: { status: string; rows?: any[] };
    disasterFetchResult?: { status: string; rows?: any[] };
    femaFetchResult?: StateAggregationResult[];
    expectedUpsertCalls: { repoName: string; count: number }[];
    expectedRepoData?: Record<string, any[]>;
  }

  const testTable: TestCase[] = [
    {
      name: 'syncAgenciesAndSpending upserts a new agency',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 0, name: 'Test Agency', abbreviation: 'TA', toptierCode: 'ABC' }
      ]},
      expectedUpsertCalls: [{ repoName: 'agency', count: 1 }],
      expectedRepoData: {
        agency: [{ name: 'Test Agency', toptierCode: 'ABC' }],
      },
    },
    {
      name: 'syncAgenciesAndSpending upserts an existing agency',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 1, name: 'Updated Agency', abbreviation: 'UA', toptierCode: 'ABC' }
      ]},
      expectedUpsertCalls: [{ repoName: 'agency', count: 1 }],
      expectedRepoData: {
        agency: [{ name: 'Updated Agency', toptierCode: 'ABC' }],
      },
    },
    {
      name: 'syncAgenciesAndSpending upserts a new spending record',
      method: 'syncAgenciesAndSpending',
      agencyFetchResult: { status: 'not_found' },
      spendingFetchResult: { status: 'success', rows: [
        { id: 0, agencyId: 1, fiscalYear: 2024, quarter: 1, awardTypeLabel: 'Grant', awardTypeCodes: '', obligatedAmount: 1000, outlayAmount: 500, awardCount: 1 }
      ], total: 1},
      expectedUpsertCalls: [{ repoName: 'spending', count: 1 }],
      expectedRepoData: {
        spending: [{ agencyId: 1, fiscalYear: 2024, obligatedAmount: 1000 }],
      },
    },
    {
      name: 'syncGeography upserts a new geo snapshot',
      method: 'syncGeography',
      geoFetchResult: { status: 'success', rows: [
        { id: 0, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, agencyId: 1, scope: 'recipient', obligatedAmount: 5000, awardCount: 3, population: 1000, perCapita: 5 }
      ]},
      expectedUpsertCalls: [{ repoName: 'geo', count: 1 }],
      expectedRepoData: {
        geo: [{ stateCode: 'CA', fiscalYear: 2024 }],
      },
    },
    {
      name: 'syncDisaster upserts a new disaster funding record',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [
        { id: 0, defGroup: 'JF-3038', defCodes: 'JF-3038', stateCode: 'CA', stateName: 'California', obligatedAmount: 10000, outlayAmount: 8000, awardCount: 5, perCapita: 0, population: 0 }
      ]},
      femaFetchResult: [],
      expectedUpsertCalls: [{ repoName: 'disaster', count: 1 }],
      expectedRepoData: {
        disaster: [{ defGroup: 'JF-3038', stateCode: 'CA' }],
      },
    },
    {
      name: 'syncDisaster stores recovery ratio when no federal spending exists for the state',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [] },
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      expectedUpsertCalls: [{ repoName: 'ratio', count: 1 }],
      expectedRepoData: {
        ratio: [{ stateCode: 'CA', recoveryRatio: 0, fedSpendingObligated: 0, femaObligated: 5000 }],
      },
    },
    {
      name: 'syncDisaster aggregates federal spending per state and computes the recovery ratio',
      method: 'syncDisaster',
      disasterFetchResult: { status: 'success', rows: [
        { id: 0, defGroup: 'JF-3038', defCodes: 'JF-3038', stateCode: 'CA', stateName: 'California', obligatedAmount: 10000, outlayAmount: 8000, awardCount: 5, perCapita: 0, population: 0 }
      ]},
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      expectedUpsertCalls: [
        { repoName: 'disaster', count: 1 },
        { repoName: 'ratio', count: 1 },
      ],
      expectedRepoData: {
        disaster: [{ defGroup: 'JF-3038', stateCode: 'CA' }],
        ratio: [{ stateCode: 'CA', recoveryRatio: 2, fedSpendingObligated: 10000, femaObligated: 5000 }],
      },
    },
    {
      name: 'syncAll orchestrates all methods',
      method: 'syncAll',
      agencyFetchResult: { status: 'success', agencies: [
        { id: 0, name: 'Test Agency', abbreviation: 'TA', toptierCode: 'ABC' }
      ]},
      spendingFetchResult: { status: 'not_found' },
      geoFetchResult: { status: 'success', rows: [
        { id: 0, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, agencyId: 1, scope: 'recipient', obligatedAmount: 5000, awardCount: 3, population: 1000, perCapita: 5 }
      ]},
      disasterFetchResult: { status: 'success', rows: [] },
      femaFetchResult: [
        { stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligatedCents: 5000, declarationCount: 2, dominantIncidentType: 'Wildfire' }
      ],
      expectedUpsertCalls: [
        { repoName: 'agency', count: 1 },
        { repoName: 'geo', count: 1 },
        { repoName: 'ratio', count: 1 },
      ],
      expectedRepoData: {
        agency: [{ name: 'Test Agency' }],
        geo: [{ stateCode: 'CA' }],
        ratio: [{ stateCode: 'CA' }],
      },
    },
  ];

  beforeEach(async () => {
    const mockAgencyRepo = { upsert: jest.fn() };
    const mockSpendingRepo = { upsert: jest.fn() };
    const mockGeoRepo = { upsert: jest.fn() };
    const mockDisasterRepo = { upsert: jest.fn() };
    const mockRatioRepo = { upsert: jest.fn() };
    const mockUsaService = {
      fetchAgencies: jest.fn(),
      fetchSpendingByAgency: jest.fn(),
      fetchGeoSnapshots: jest.fn(),
      fetchDisasterSpending: jest.fn(),
    };
    const mockFemaService = {
      fetchDeclarationsByState: jest.fn(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        SyncService,
        { provide: getRepositoryToken(Agency), useValue: mockAgencyRepo },
        { provide: getRepositoryToken(SpendingRecord), useValue: mockSpendingRepo },
        { provide: getRepositoryToken(GeoSpendingSnapshot), useValue: mockGeoRepo },
        { provide: getRepositoryToken(DisasterFundingRecord), useValue: mockDisasterRepo },
        { provide: getRepositoryToken(DisasterRecoveryRatio), useValue: mockRatioRepo },
        { provide: UsaSpendingService, useValue: mockUsaService },
        { provide: OpenFemaService, useValue: mockFemaService },
      ],
    }).compile();

    service = module.get<SyncService>(SyncService);
    agencyRepo = module.get(getRepositoryToken(Agency));
    spendingRepo = module.get(getRepositoryToken(SpendingRecord));
    geoRepo = module.get(getRepositoryToken(GeoSpendingSnapshot));
    disasterRepo = module.get(getRepositoryToken(DisasterFundingRecord));
    ratioRepo = module.get(getRepositoryToken(DisasterRecoveryRatio));
    usaService = module.get<UsaSpendingService>(UsaSpendingService);
    femaService = module.get<OpenFemaService>(OpenFemaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it.each(testTable)('$name', async ({
    method,
    agencyFetchResult,
    spendingFetchResult,
    geoFetchResult,
    disasterFetchResult,
    femaFetchResult,
    expectedUpsertCalls,
    expectedRepoData,
  }) => {
    usaService.fetchAgencies.mockResolvedValue({ status: 'not_found' });
    usaService.fetchSpendingByAgency.mockResolvedValue({ status: 'not_found' });
    usaService.fetchGeoSnapshots.mockResolvedValue({ status: 'not_found' });
    usaService.fetchDisasterSpending.mockResolvedValue({ status: 'not_found' });
    femaService.fetchDeclarationsByState.mockResolvedValue([]);

    if (agencyFetchResult) usaService.fetchAgencies.mockResolvedValue(agencyFetchResult);
    if (spendingFetchResult) usaService.fetchSpendingByAgency.mockResolvedValue(spendingFetchResult);
    if (geoFetchResult) usaService.fetchGeoSnapshots.mockResolvedValue(geoFetchResult);
    if (disasterFetchResult) usaService.fetchDisasterSpending.mockResolvedValue(disasterFetchResult);
    if (femaFetchResult) femaService.fetchDeclarationsByState.mockResolvedValue(femaFetchResult);

    await (service as Record<string, unknown>)[method]();

    for (const call of expectedUpsertCalls) {
      const repo = getRepo(call.repoName);
      const upsertCalls = (repo.upsert as jest.Mock).mock.calls;
      expect(upsertCalls.length).toBe(call.count);
    }

    if (expectedRepoData) {
      for (const [repoName, expectedData] of Object.entries(expectedRepoData)) {
        const repo = getRepo(repoName);
        const upsertCalls = (repo.upsert as jest.Mock).mock.calls;
        for (let i = 0; i < upsertCalls.length; i++) {
          const upserted = upsertCalls[i][0];
          const expected = (expectedData as any[])[i];
          for (const [key, value] of Object.entries(expected)) {
            expect(upserted[key]).toBe(value);
          }
        }
      }
    }
  });

  function getRepo(name: string): { upsert: jest.Mock } {
    switch (name) {
      case 'agency': return { upsert: agencyRepo.upsert };
      case 'spending': return { upsert: spendingRepo.upsert };
      case 'geo': return { upsert: geoRepo.upsert };
      case 'disaster': return { upsert: disasterRepo.upsert };
      case 'ratio': return { upsert: ratioRepo.upsert };
    }
  }
});

import { Injectable } from '@nestjs/common';
import { Agency } from '../agencies/agency.entity';
import { SpendingRecord } from '../spending/spending-record.entity';
import { GeoSpendingSnapshot } from '../geography/geo-spending-snapshot.entity';
import { DisasterFundingRecord } from '../disaster/disaster-funding-record.entity';
import {
  RawUsaSpendingAgencyRow,
  RawUsaSpendingGeoRow,
  RawUsaSpendingDefCodeRow,
} from './usa-spending.types';

const MAX_ATTEMPTS = 3;
const BASE_DELAY_MS = 500;

const API_BASE = 'https://api.usaspending.gov/api/v2';

type FetchSpendingResult =
  | { status: 'success'; rows: SpendingRecord[]; total: number }
  | { status: 'not_found' };

type FetchGeoResult =
  | { status: 'success'; rows: GeoSpendingSnapshot[] }
  | { status: 'not_found' };

type FetchDisasterResult =
  | { status: 'success'; rows: DisasterFundingRecord[] }
  | { status: 'not_found' };

type FetchAgenciesResult =
  | { status: 'success'; agencies: Agency[] }
  | { status: 'not_found' };

type FetchDefCodesResult =
  | { status: 'success'; defCodes: RawUsaSpendingDefCodeRow[] }
  | { status: 'not_found' };

const transformGeoRows = (
  rows: RawUsaSpendingGeoRow[],
  scope: string,
  fiscalYear: number,
): GeoSpendingSnapshot[] =>
  rows.map((r) => ({
    id: undefined as any,
    stateCode: r.shape_code || '',
    stateName: r.display_name || '',
    fiscalYear,
    agencyId: null as any,
    scope,
    obligatedAmount: Math.round(r.aggregated_amount * 100),
    awardCount: 0,
    population: r.population || 0,
    perCapita: Math.round((r.per_capita || 0) * 100),
    agency: null as any,
  })) as GeoSpendingSnapshot[];

const fetchWithRetry = async (
  url: string,
  options: RequestInit = {},
): Promise<unknown> => {
  let lastError: Error | undefined;

  for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
    try {
      const response = await fetch(url, options);

      if (!response.ok) {
        throw new Error(
          `HTTP ${response.status}: ${response.statusText}`,
        );
      }

      return await response.json();
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));

      if (attempt < MAX_ATTEMPTS) {
        const delay = BASE_DELAY_MS * Math.pow(2, attempt - 1);
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw lastError;
};

const fetchAllPages = async (
  baseUrl: string,
  baseBody: Record<string, unknown>,
): Promise<unknown[]> => {
  const firstBody = (await fetchWithRetry(baseUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ ...baseBody, page: 1 }),
  })) as {
    results: unknown[];
    page_metadata?: { has_next?: boolean; total?: number; page?: number };
  };

  const allRows: unknown[] = [...(firstBody.results || [])];

  if (firstBody.page_metadata?.has_next) {
    let page = 2;
    while (true) {
      const pageBody = (await fetchWithRetry(baseUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...baseBody, page }),
      })) as { results: unknown[]; page_metadata?: { has_next?: boolean } };
      allRows.push(...(pageBody.results || []));
      if (!pageBody.page_metadata?.has_next) break;
      page++;
    }
  }

  return allRows;
};

@Injectable()
export class UsaSpendingService {
  async fetchAgencies(): Promise<FetchAgenciesResult> {
    const rawData = await fetchWithRetry(
      `${API_BASE}/references/toptier_agencies/`,
    );
    const body = rawData as { results: RawUsaSpendingAgencyRow[] };

    const agencies: Agency[] = body.results.map((r) => ({
      id: undefined as any,
      name: r.agency_name || '',
      abbreviation: r.abbreviation || '',
      toptierCode: r.toptier_code,
    }));

    return agencies.length > 0
      ? { status: 'success', agencies }
      : { status: 'not_found' };
  }

  async fetchSpendingByAgency(
    params: { agency: string; fiscalYear: number },
  ): Promise<FetchSpendingResult> {
    if (!params.agency) return { status: 'not_found' };

    const body = {
      filters: {
        time_period: [{
          start_date: `${params.fiscalYear}-10-01`,
          end_date: `${params.fiscalYear + 1}-09-30`,
        }],
      },
      geo_layer: 'state',
      scope: 'recipient_location',
    };

    const allRows = await fetchAllPages(
      `${API_BASE}/search/spending_by_geography/`,
      body,
    );

    const rawGeo = allRows as RawUsaSpendingGeoRow[];
    const transformed = transformGeoRows(rawGeo, 'recipient_location', params.fiscalYear).map(
      (r) => ({
        ...r,
        id: undefined as any,
        agencyId: parseInt(params.agency, 10) || 0,
        fiscalYear: params.fiscalYear,
        quarter: 1,
        awardTypeLabel: '',
        awardTypeCodes: '',
        outlayAmount: 0,
      }) as SpendingRecord,
    );

    return transformed.length > 0
      ? { status: 'success', rows: transformed, total: rawGeo.length }
      : { status: 'not_found' };
  }

  async fetchGeoSnapshots(
    params: { agency: string; fiscalYear: number; scope: string },
  ): Promise<FetchGeoResult> {
    const scopeMap: Record<string, string> = {
      recipient: 'recipient_location',
      performance: 'place_of_performance',
    };
    const body = {
      filters: {
        time_period: [{
          start_date: `${params.fiscalYear}-10-01`,
          end_date: `${params.fiscalYear + 1}-09-30`,
        }],
      },
      geo_layer: 'state',
      scope: scopeMap[params.scope] || params.scope,
    };

    const allRows = await fetchAllPages(
      `${API_BASE}/search/spending_by_geography/`,
      body,
    );

    const rawGeo = allRows as RawUsaSpendingGeoRow[];
    const transformed = transformGeoRows(rawGeo, params.scope, params.fiscalYear);

    return transformed.length > 0
      ? { status: 'success', rows: transformed }
      : { status: 'not_found' };
  }

  async fetchDisasterSpending(
    defGroup: string,
  ): Promise<FetchDisasterResult> {
    const body = {
      filters: {
        time_period: [{
          start_date: '2024-10-01',
          end_date: '2025-09-30',
        }],
        def_codes: [defGroup],
      },
      geo_layer: 'state',
      scope: 'recipient_location',
    };

    const allRows = await fetchAllPages(
      `${API_BASE}/search/spending_by_geography/`,
      body,
    );

    const rawGeo = allRows as RawUsaSpendingGeoRow[];
    const transformed = transformGeoRows(rawGeo, 'recipient_location', 2024).map(
      (r) => ({
        ...r,
        id: undefined as any,
        defGroup,
        defCodes: defGroup,
      }) as DisasterFundingRecord,
    );

    return transformed.length > 0
      ? { status: 'success', rows: transformed }
      : { status: 'not_found' };
  }

  async fetchDefCodes(): Promise<FetchDefCodesResult> {
    const rawData = await fetchWithRetry(
      `${API_BASE}/references/def_codes/`,
    );
    const body = rawData as { codes: RawUsaSpendingDefCodeRow[] };

    const defCodes: RawUsaSpendingDefCodeRow[] = body.codes.map((r) => ({
      code: r.code,
      label: r.label,
      group: r.group,
    }));

    return defCodes.length > 0
      ? { status: 'success', defCodes }
      : { status: 'not_found' };
  }
}

export function computeRecoveryRatio(
  femaCents: number,
  fedCents: number,
): number {
  if (Number.isNaN(femaCents) || Number.isNaN(fedCents)) return 0;
  if (femaCents === 0 && fedCents === 0) return 1.0;
  if (femaCents === 0) return 0;
  if (fedCents === 0) return 0;
  return fedCents / femaCents;
}

import { computeRecoveryRatio } from './recovery-ratio';

describe('computeRecoveryRatio', () => {
  interface TestCase {
    name: string;
    femaCents: number;
    fedCents: number;
    expected: number;
  }

  const testTable: TestCase[] = [
    {
      name: 'both zero returns neutral 1.0',
      femaCents: 0,
      fedCents: 0,
      expected: 1.0,
    },
    {
      name: 'fema zero fed positive returns 0',
      femaCents: 0,
      fedCents: 50000,
      expected: 0,
    },
    {
      name: 'fema positive fed zero returns 0',
      femaCents: 50000,
      fedCents: 0,
      expected: 0,
    },
    {
      name: 'both positive returns fed divided by fema',
      femaCents: 50000,
      fedCents: 125000,
