    },
    {
      name: 'both NaN returns 0',
      femaCents: NaN,
      fedCents: NaN,
      expected: 0,
    },
  ];

  it.each(testTable)('$name', ({ femaCents, fedCents, expected }) => {
    expect(computeRecoveryRatio(femaCents, fedCents)).toBe(expected);
  });
});
